package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.Reader;
import java.io.StringReader;
import java.lang.reflect.Field;

class Gson_newJsonReader_Test {

  private Gson gson;

  @BeforeEach
  public void setUp() throws Exception {
    // Create Gson instance with lenient = true using reflection to call constructor
    Field lenientField = Gson.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);

    // Use default constructor and then set lenient field to true
    gson = new Gson();
    lenientField.set(gson, true);
  }

  @Test
  public void testNewJsonReader_withLenientTrue() throws Exception {
    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);

    JsonReader jsonReader = gson.newJsonReader(reader);

    assertNotNull(jsonReader);

    // Use reflection to get the 'in' field from JsonReader (the Reader passed in constructor)
    Field inField = JsonReader.class.getDeclaredField("in");
    inField.setAccessible(true);
    Object actualReader = inField.get(jsonReader);

    assertSame(reader, actualReader);
    // lenient should be true as set by reflection
    assertTrue(jsonReader.isLenient());
  }

  @Test
  public void testNewJsonReader_withLenientFalse() throws Exception {
    // Create a new Gson instance with lenient = false using reflection
    gson = new Gson();
    Field lenientField = Gson.class.getDeclaredField("lenient");
    lenientField.setAccessible(true);
    lenientField.set(gson, false);

    String json = "{\"key\":\"value\"}";
    Reader reader = new StringReader(json);

    JsonReader jsonReader = gson.newJsonReader(reader);

    assertNotNull(jsonReader);

    // Use reflection to get the 'in' field from JsonReader (the Reader passed in constructor)
    Field inField = JsonReader.class.getDeclaredField("in");
    inField.setAccessible(true);
    Object actualReader = inField.get(jsonReader);

    assertSame(reader, actualReader);
    // lenient should be false
    assertFalse(jsonReader.isLenient());
  }

  @Test
  public void testNewJsonReader_withNullReader() {
    assertThrows(NullPointerException.class, () -> {
      gson.newJsonReader(null);
    });
  }
}
